Edit this javascript function to add these features to the force directed graph:  
1. When the user hovers over a node, highlight all first degree nodes and links connected to it and grey out all other nodes and links (set color to grey and reduce transparency).  
2. When the user drags a node and releases, freeze the node in it’s place  
3. When the user clicks on a node that was frozen, unfreeze it so that it interacts with the forces again.  

Below is the current function:  
```  
d3_force_directed_graph = (
        data,
        link_force = 0.5,
        repel_force = -250,
        center_force = 0.5,
        zoom_factor = 1,
      ) => {
        // Specify the dimensions of the chart.
        const width = 1000;
        const height = 1000;

        // Specify the color scale.
        const color = d3.scaleOrdinal(d3.schemeCategory10);

        // Create copies of the links and nodes data.
        const links = data.links.map(d => ({...d}));
        const nodes = data.nodes.map(d => ({...d}));

        // Create a simulation with several forces.
        const simulation = d3.forceSimulation(nodes)
          .force("link", d3.forceLink(links).id(d => d.id).strength(link_force))
          .force("charge", d3.forceManyBody().strength(repel_force))
          .force("center", d3.forceCenter(width / 2, height / 2).strength(center_force))
          .on("tick", ticked);

        // Create the SVG container with zoom capabilities.
        const svg = d3.create("svg")
          .attr("width", width)
          .attr("height", height)
          .attr("viewBox", [0, 0, width, height])
          .attr("style", "max-width: 100%; height: auto;")
          .call(d3.zoom().scaleExtent([0.1, 10]).on("zoom", (event) => {
            g.attr("transform", event.transform);
          }));

        // Create a group element for zooming purposes.
        const g = svg.append("g")
          .attr("transform", `scale(${zoom_factor})`);

        // Add a line for each link.
        const link = g.append("g")
          .attr("stroke", "#999")
          .attr("stroke-opacity", 0.6)
          .selectAll()
          .data(links)
          .join("line")
          .attr("stroke-width", d => Math.sqrt(d.value));

        // Add a circle for each node.
        const node = g.append("g")
          .attr("stroke", "#fff")
          .attr("stroke-width", 1.5)
          .selectAll()
          .data(nodes)
          .join("circle")
          .attr("r", 7)
          .attr("fill", d => color(d.group));

        // Add labels to each node.
        const label = g.append("g")
          .selectAll("text")
          .data(nodes)
          .join("text")
          .text(d => d.id)
          .attr("x", 6)
          .attr("y", 3);

        // Add a drag behavior.
        node.call(d3.drag()
          .on("start", dragstarted)
          .on("drag", dragged)
          .on("end", dragended));

        // Set the position attributes of links, nodes, and labels each time the simulation ticks.
        function ticked() {
          link
            .attr("x1", d => d.source.x)
            .attr("y1", d => d.source.y)
            .attr("x2", d => d.target.x)
            .attr("y2", d => d.target.y);

          node
            .attr("cx", d => {
              if (d.x < 0) {
                d.vx = Math.abs(d.vx);
                d.x = 0;
              } else if (d.x > width) {
                d.vx = -Math.abs(d.vx);
                d.x = width;
              }
              return d.x;
            })
            .attr("cy", d => {
              if (d.y < 0) {
                d.vy = Math.abs(d.vy);
                d.y = 0;
              } else if (d.y > height) {
                d.vy = -Math.abs(d.vy);
                d.y = height;
              }
              return d.y;
            });

          label
            .attr("x", d => d.x + 6)
            .attr("y", d => d.y + 3);
        }

        // Reheat the simulation when drag starts, and fix the subject position.
        function dragstarted(event) {
          if (!event.active) simulation.alphaTarget(0.3).restart();
          event.subject.fx = event.subject.x;
          event.subject.fy = event.subject.y;
        }

        // Update the subject (dragged node) position during drag.
        function dragged(event) {
          event.subject.fx = event.x;
          event.subject.fy = event.y;
        }

        // Restore the target alpha so the simulation cools after dragging ends.
        // Unfix the subject position now that it’s no longer being dragged.
        function dragended(event) {
          if (!event.active) simulation.alphaTarget(0);
          event.subject.fx = null;
          event.subject.fy = null;
        }

        return svg.node();
    }
```

